import re, pathlib
p = pathlib.Path('/Users/gbang/Downloads/algora/workspace/2c1c09b2-95a1-465b-a31b-39030cf73fcf_hld/_response.md')
md = p.read_text(encoding='utf-8')
blocks = re.findall(r'```mermaid(.*?)```', md, flags=re.S)
breaking = set(':;/"<>{}')   # NOTE: exclude ( ) since those are cylinder shape delimiters
problems = []
for bi, b in enumerate(blocks):
    for line in b.splitlines():
        s = line.strip()
        # cylinder label text is between [( and )]
        for lab in re.findall(r'\[\((.*?)\)\]', s):
            for ch in lab:
                if ch in breaking or ch in '()[]':
                    problems.append((bi,'cyl',lab,ch))
        # plain box / queue label text: strip outer brackets then check
        for lab in re.findall(r'\[\[(.*?)\]\]', s):   # queue
            for ch in lab:
                if ch in breaking or ch in '()[]':
                    problems.append((bi,'queue',lab,ch))
        for lab in re.findall(r'(?<!\[)\[([^\[\]]*?)\](?!\])', s):  # plain box, not [[ or [(
            for ch in lab:
                if ch in breaking or ch in '()[]':
                    problems.append((bi,'box',lab,ch))
        # edge labels |"..."|
        for lab in re.findall(r'\|"(.*?)"\|', s):
            for ch in lab:
                if ch in breaking or ch in '()[]':
                    problems.append((bi,'edge',lab,ch))
print("REAL breaking-char problems in label TEXT =", len(problems))
for x in problems: print("   ", x)
print("All clean" if not problems else "FIX NEEDED")
